const r={INTRO:{title:"委托",lines:[{speaker:"德尔芬",text:"我有一张种植园的地图，但目前只知道书房这一个位置。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"我已经拿到了当时在场所有人的照片。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"但我只知道委托人的父亲和妹妹的名字。在开始调查其他人之前，我需要先弄清楚他们的姓名。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"好了，先去书房看看能不能找到什么线索。",portrait:"portraits/investigator.png"}]},STUDY_ZERO:{title:"锚定记忆",lines:[{speaker:"德尔芬",text:"当我全神贯注时，就能感受到书房的本质，就像我真的身处那个房间一样。这种感觉很难用语言描述，很多人认为只是糊弄人的把戏，我觉得也情有可原。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"老房间都有一种特殊的氛围。构成空间本质的物品会成为房间的一部分。在那个空间里放置得足够久的物品，会与空间本身“锚定”在一起。",portrait:"portraits/investigator.png"}]},PHONE_TIP:{title:"注入记忆的物品",lines:[{speaker:" ",text:"德尔芬可以将注意力集中在物品上，比如这里的电话。"},{speaker:" ",text:"可以前往物品栏（或在任何地方按i键）找到电话，通过将它与正确的所有者关联来进行“感应”。"},{speaker:" ",text:"一旦确认了所有者，德尔芬就能感受到该所有者在任何时间使用该物品时的气场，并看到在它面前发生之事的记忆回响。"},{speaker:"德尔芬",text:"既然杰里迈亚是种植园的主人，他很可能是最常使用电话的人，因此我大概率需要将电话与他关联。",portrait:"portraits/investigator.png"}]},LINES:{lines:[{speaker:"德尔芬",text:"临时军营通常被称为“战线”，是由当地材料搭建的棚屋，而不是帐篷。",portrait:"portraits/investigator.png"}]},STUDY_ONE:{title:"书房的回响",lines:[{speaker:"德尔芬",text:"我知道杰里迈亚下午4点独自在书房里。如果我集中精力在杰里迈亚身上，应该能看到那里发生的记忆回响。",portrait:"portraits/investigator.png"},{speaker:" ",text:"将时间线设置为16:00，并将杰里迈亚的照片置于焦点中。"},{speaker:" ",text:"一名宾客在任何给定时间只能处于一个地点。如果在一个地点看到一名宾客，TA就不可能同时出现在另一个地点。"},{speaker:" ",text:"事件不一定占用一整个小时，但在一个地点一次只能发生一个重要事件。"},{speaker:" ",text:"宾客可能会在一个房间的回响边缘出现，而在该时段的剩余时间里位于另一个房间。宾客只有完全存在于一个房间内才算作位于该房间。"}]},LIBRARY_WARNING:{title:"缺失证据",lines:[{speaker:"德尔芬",text:"我还没有足够的证据在图书馆里进行调查。现在应该把重点放在那位不速之客的到来上。",portrait:"portraits/investigator.png"}]},STUDY_11:{title:"电话通话",branches:[{check:t=>!t.unlockedPeople.has("p10")&&!t.unlockedPeople.has("p9"),lines:[{speaker:"德尔芬",text:"房间里还有一个叫田中次郎（Jiro）的人和那个打电话的人在一起。一旦我弄清楚他们俩是谁，我应该再回到这里，看看完整的对话。",portrait:"portraits/investigator.png"}]},{check:t=>!t.unlockedPeople.has("p10"),lines:[{speaker:"德尔芬",text:"房间里还有一个叫次郎的人和卡南在一起。弄清楚他是谁之后，我应该再回到这里，看看他那部分的对话。",portrait:"portraits/investigator.png"}]},{check:t=>t.unlockedPeople.has("p10"),lines:[{speaker:"德尔芬",text:"我现在知道次郎和卡南都在书房里，可以通过聚焦他们两人来解锁完整的回响。",portrait:"portraits/investigator.png"}]}]},STUDY_11_2:{title:"电话通话",lines:[{speaker:"德尔芬",text:"房间里还有一个叫次郎的人和卡南在一起。弄清楚他是谁之后，我应该再回到这里，看看他那部分的对话。",portrait:"portraits/investigator.png"}]},DEDUCTION_HELP:{title:"新策略",lines:[{speaker:"德尔芬",text:"两个陌生人……我有他们的照片，现在也有了他们的名字。婆罗洲的原住民通常没有姓氏，所以我应该能仅凭名字就认出卡南。",portrait:"portraits/investigator.png"},{speaker:" ",text:"如果德尔芬能根据语境猜出宾客的身份，就可以在文件中将名字与面孔关联起来。"}]},TELEPHONE_0:{title:"手摇电话",lines:[{speaker:"德尔芬",text:"这部电话附着着很强的能量。我能清楚地感觉到，凌晨2点，一个带有婆罗洲口音的男人在使用它。",portrait:"portraits/investigator.png"},{speaker:" ",text:"现在德尔芬已经将气场与电话相连，她能感知到任何时间是谁在使用它。"},{speaker:" ",text:"但她只能听到和感觉到正在使用或拿着该物品的人，无法感知到房间里的其他人。"}]},GHOST_IMAGE:{title:"幽灵残影",lines:[{speaker:"德尔芬",text:"天哪！那道闪光……镜子里的那个影像……",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"虽然很微弱，但这心灵印记是不可否认的。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"闪光的强度太大了，在以太中留下了印记。这股能量足够强。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"有了这个锚点，我就能追踪他。现在能感觉到他在种植园里的活动轨迹了。",portrait:"portraits/investigator.png"}]},SHAMAN_NAME:{title:"萨满",lines:[{speaker:"德尔芬",text:"巴巴利安·安陶……一位强大的萨满。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"我怀疑能不能找到他的照片。他太隐秘了，隐藏在历史的阴影中。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"我必须通过其他方式推断他的存在。如果想拼凑出他的行踪，我就得换个思路才行。",portrait:"portraits/investigator.png"}]},TUAN_BESAR:{title:"图安",theme:"british_standards",lines:[{speaker:"德尔芬",text:"在种植园里，图安（先生/老爷）是对管理者的标准尊称，而大图安则是负责整个庄园的最高管理者。在这里，卡南指的是杰里迈亚·古德威尔。",portrait:"portraits/investigator.png"}]},MEM:{title:"女主人",theme:"british_standards",lines:[{speaker:"德尔芬",text:"女主人（Mem）是对“当家主母”的专门称呼。我猜“小主人”是仆人们对卢恩的昵称。",portrait:"portraits/investigator.png"}]},CONSTABULARY:{title:"警备队",theme:"maritime_rules",lines:[{speaker:"德尔芬",text:"北婆罗洲武装警备队海事分队，是英国管辖的北婆罗洲地区最接近海岸警卫队的组织。在日本入侵前，他们会驾驶着小型的武装摩托艇在海岸线上巡逻。",portrait:"portraits/investigator.png"}]},PIRACY_GRILLE:{theme:"piracy",title:"铁栅",lines:[{speaker:"德尔芬",text:"海盗劫持的威胁非常普遍，以至于在1920年代，蒸汽船都配备了防海盗铁栅——将舰桥和头等舱与船只其余部分隔开的沉重铁条和铁门，实质上将船员区围成了一个堡垒。",portrait:"portraits/investigator.png"}]},GAYUNG:{title:"Gayung",theme:"british_standards",lines:[{speaker:"德尔芬",text:"Gayung是一种传统的塑料或金属长柄勺，用于从水缸或水桶中舀水洗澡。",portrait:"portraits/investigator.png"}]},SHANGAI_JAR:{title:"上海水缸",theme:"british_standards",lines:[{speaker:"德尔芬",text:"殖民地的房屋中常使用巨大的陶瓷“上海水缸”来储存凉水，以便在热带高温下洗澡。",portrait:"portraits/investigator.png"}]},FEVER:{title:"热病",theme:"tropical_killers",lines:[{speaker:"德尔芬",text:"卢恩指的一定是黑水热，这绝对是热带地区年轻欧洲人最惧怕的死因。它是反复感染疟疾后产生的一种可怕并发症，几天内就会致命。",portrait:"portraits/investigator.png"}]},STARCHED_WHITES:{title:"浆洗白衣",theme:"british_standards",lines:[{speaker:"德尔芬",text:"浆洗得笔挺的白色衣服是殖民地男性在家中的标准着装。白色的短裤、及膝白袜和白衬衫，干净笔挺，通常带有薰衣草或类似的香味。这种服装在干活时一点也不实用，但可以为一些思想拙劣的英国人提供优越感错觉。",portrait:"portraits/investigator.png"}]},SABAH:{title:"沙巴",theme:"colonies",lines:[{speaker:"德尔芬",text:"沙巴是婆罗洲最大的州，西接沙捞越州和加里曼丹，东临菲律宾。它由英国北婆罗洲渣打公司统治，这是一家在19世纪获得英国政府皇家特许状的私人公司。",portrait:"portraits/investigator.png"}]},SUNDOWNER:{title:"夕暮酒",theme:"culture",lines:[{speaker:"德尔芬",text:"我的研究表明，夕暮酒是当地的俗语，指的是日落时分喝的一杯晚饮，标志着白天的高温向夜晚的凉爽过渡。",portrait:"portraits/investigator.png"}]},GIN_PAHITS:{title:"苦金酒",theme:"culture",lines:[{speaker:"德尔芬",text:"苦金酒是一种混合了大量安哥斯图拉苦精的金酒，能帮助在潮湿的热带丛林中度过一天的人们调理肠胃。",portrait:"portraits/investigator.png"}]},SMALL_CHOPS:{title:"佐酒小吃",theme:"culture",lines:[{speaker:"德尔芬",text:"这是当地对配夕暮酒的零食的称呼。它们的口味设计得很重，用来刺激味蕾，让人们多喝酒。",portrait:"portraits/investigator.png"}]},TOBACCO_TRADE_IS_DRYING_UP:{title:"烟草贸易日渐式微",theme:"colonies",lines:[{speaker:"德尔芬",text:"30年前，北婆罗洲以其高品质的雪茄外包叶闻名于世。然而到了1930年代，由于纸烟变得更流行，加上土壤枯竭，许多烟草公司开始结业或转种橡胶和椰子。看来古德威尔家落后于时代，并感受到了压力。",portrait:"portraits/investigator.png"}]},BAJAU:{title:"巴瑶族",theme:"pearls",lines:[{speaker:"德尔芬",text:"巴瑶族是一支生活在婆罗洲周边水域的游牧海上民族。他们是优秀的潜水员，也是珍珠专家。",portrait:"portraits/investigator.png"}]},TOWKAY:{title:"头家",theme:"pearls",lines:[{speaker:"德尔芬",text:"头家（中国商人）战前在北婆罗洲控制珍珠贸易，是强大而有影响力的商人。",portrait:"portraits/investigator.png"}]},KORNBRAND:{title:"科恩酒",theme:"culture",lines:[{speaker:"德尔芬",text:"Kornbrand是德国的一种谷物烈酒，非常像伏特加，但通常蒸馏的酒精度略低，以保留谷物的风味。在英国人看来它可能就像伏特加，但对于德国人或俄罗斯人来说，区别还是很明显的。",portrait:"portraits/investigator.png"}]},SUNNING:{title:"桑宁号",theme:"piracy",lines:[{speaker:"德尔芬",text:"桑宁号是一艘在1926年被海盗劫持的蒸汽船。",portrait:"portraits/investigator.png"}]},TUAN_DOSE:{title:"图安药剂",theme:"tropical_killers",lines:[{speaker:"德尔芬",text:"奎宁通常伴着夕暮酒和晚间小吃一起吞下，因为人们认为不应该空腹服用。婆罗洲几乎所有人每天都会吃来预防疟疾。",portrait:"portraits/investigator.png"}]},QUININE:{title:"奎宁",theme:"tropical_killers",lines:[{speaker:"德尔芬",text:"奎宁通常伴着夕暮酒和晚间小吃一起吞下，因为人们认为不应该空腹服用。婆罗洲几乎所有人每天都会吃来预防疟疾。",portrait:"portraits/investigator.png"}]},SALLOW:{title:"黄疸",theme:"tropical_killers",lines:[{speaker:"德尔芬",text:"黄疸用来描述感染了疟疾的欧洲人脸上和手上呈现出的微黄皮肤，是慢性疾病的标志。",portrait:"portraits/investigator.png"}]},BIAS_BAY:{title:"大亚湾",theme:"piracy",lines:[{speaker:"德尔芬",text:"大亚湾是广东沿海的一个隐蔽海湾，在海盗的黄金时代，它曾是一个海盗共和国。",portrait:"portraits/investigator.png"}]},STRAITS_STEAMSHIP:{title:"海峡轮船",theme:"the_seas",lines:[{speaker:"德尔芬",text:"海峡轮船是古德威尔家将货物和人员从大陆运往婆罗洲的主要途径。这是一条定期航线，但也是海盗的目标。",portrait:"portraits/investigator.png"}]},SANDAKAN:{title:"山打根",theme:"colonies",lines:[{speaker:"德尔芬",text:"山打根是英属北婆罗洲的首府，也是该地区最大的城市。这是一个充满极端反差的地方：一个被广袤狂野的丛林和毫无法纪的海洋包围的精致英国行政中心。它在战争结束时被彻底摧毁了。",portrait:"portraits/investigator.png"}]},KACHANG:{theme:"culture",lines:[{speaker:"德尔芬",text:"Kachang在马来语中是“豆”或“坚果”的意思，通常指用香料烤制的花生。",portrait:"portraits/investigator.png"}]},BLACK_SMOKE:{theme:"japanese_invasion",lines:[{speaker:"德尔芬",text:"当日本入侵迫在眉睫时，荷兰人炸毁了炼油厂，并点燃了美里和巴厘巴板的油井。婆罗洲上空都被染成了黑色，持续了几个星期之久。",portrait:"portraits/investigator.png"}]},CHANDU:{theme:"opium",lines:[{speaker:"德尔芬",text:"禅杜是精炼的鸦片，经过煮沸和发酵制成糖浆状的膏体。在许多殖民地，它是政府专营的垄断商品。",portrait:"portraits/investigator.png"}]},DROSS:{theme:"opium",lines:[{speaker:"德尔芬",text:"膏渣是吸食鸦片膏后留下的，类似木炭的有毒残留物。人们通常将它刮出来，与新鲜的鸦片重新混合，或者被买不起精制禅杜的瘾君子吸食。",portrait:"portraits/investigator.png"}]},LAMP:{lines:[{speaker:"德尔芬",text:"蒂利灯，英国殖民地标准的加压煤油灯。",portrait:"portraits/investigator.png"}]},KOTA_BHARU:{title:"哥打巴鲁",lines:[{speaker:"德尔芬",text:"马来亚东北部的哥打巴鲁是一个重要的军事热点，也是太平洋战争第一场重大战役的发生地。",portrait:"portraits/investigator.png"}]},RUNDUM_REBELLION:{title:"伦顿叛乱",theme:"colonies",lines:[{speaker:"德尔芬",text:"1915年的伦顿叛乱是毛律人对英国北婆罗洲渣打公司的最后一次大规模起义，由公司的税收政策和强迫劳动引发。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"以sumpitans，也就是马来吹箭筒闻名的毛律人，在内陆茂密的丛林中建造了错综复杂的地下堡垒。对于年轻的殖民地军官来说，在敌人的地盘上与看不见的对手作战是非常可怕的经历。",portrait:"portraits/investigator.png"}]},TUJU:{title:"Tuju",theme:"occult",lines:[{speaker:"德尔芬",text:"Tuju是一种诅咒，由萨满（Bomoh）通过法术将某种物体送入受害者的体内以致其死亡。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"受害者会遭受突如其来且无法解释的剧痛（刺痛或颤抖），而西医却查不出任何毛病。这是一个可怕的概念，融合了心理战和根深蒂固的迷信。",portrait:"portraits/investigator.png"}]},AISYAH_NAME:{title:"女仆",lines:[{speaker:"德尔芬",text:"艾莎肯定是个当地的女仆。我这些照片里只有一个，应该就是她了，可以标记出来。",portrait:"portraits/investigator.png",action:"unlock_p11"}]},PIRATE_CAPTAIN:{title:"海盗船长",lines:[{speaker:"德尔芬",text:"（思考）那个男人……路德维希·哈罗。他举手投足间像个国王，而不是个普通的强盗。他会臭名昭著到上过报纸吗？",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"（思考）不管怎样，我都得打电话给阿尔芒，问问求救电话的事。正好可以请他查一下档案里关于哈罗船长的资料。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"（电话音）阿尔芒？我是德尔芬。请听仔细了，我有一份从种植园打出的马来语电话转录。你能不能翻译一下？“...Goo-dwill... ma-ti... British... Navy...”？",portrait:"portraits/investigator.png"},{speaker:"阿尔芒",text:"（电话音）德尔芬……*叹气*。我的马来语已经生疏了，但“mati”是死的意思。听起来他是声称杰里迈亚·古德威尔被海盗谋杀了，并请求英国海军立即支援。他们应该在第二天早上09:00抵达。",portrait:"portraits/armand.jpeg"},{speaker:"德尔芬",text:"真有效率。他描绘了一场屠杀，以确保迅速、强有力的回应。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"既然接通了，我还有个请求。听起来可能很奇怪，但请听我说完。这些海盗的首领是一个叫路德维希·哈罗的人。我希望能从哪里找到关于他的一些资料。",portrait:"portraits/investigator.png"},{speaker:"阿尔芒",text:"（电话音）哈罗？这真是让人意外。他是个传奇人物，德尔芬，不是因为做海盗，而是因为那场战争。他领导了一支游击队反抗日军的占领，从山打根死亡行军中救下了数百人。",portrait:"portraits/armand.jpeg"},{speaker:"阿尔芒",text:"（电话音）在历史书上他是个英雄。居然在成为英雄之前在这扮演着恶棍的角色……真有意思。我从档案中找到了他的服役照片，之后给你发过去。",portrait:"portraits/armand.jpeg",action:"unlock_p13"},{speaker:"德尔芬",text:"太好了，谢谢你，阿尔芒。",portrait:"portraits/investigator.png"}]},EPILOGUE:{title:"结案",lines:[{speaker:"德尔芬",text:"我们做到了，古德威尔先生。真相终于大白了。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"您的妹妹卢恩并没有葬身火海。她在那天晚上活了下来，逃出了种植园。希望她在英国这里展开了新的生活。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"希望这能为您带来寻觅已久的平静。如果您希望结案，我们可以在此停手，但我相信还有很多信息有待发掘。",portrait:"portraits/investigator.png",action:"credits"}]},IRON_ROAD:{title:"铁道",theme:"colonies",lines:[{speaker:"德尔芬",text:"北婆罗洲铁路是一个纯粹由英国主导的项目，也是整个岛上唯一的铁路系统。沿海的种植园都被设计为连接到这条铁路线，这条铁路也被用来向山打根港口双向运输货物。",portrait:"portraits/investigator.png"}]},BROOKE_RAJAHS:{title:"布鲁克拉贾",theme:"colonies",lines:[{speaker:"德尔芬",text:"婆罗洲的英国管辖部分被分为三个领地：由布鲁克家族（也被称为白人拉贾）统治的沙捞越州，由英国北婆罗洲渣打公司统治的英属北婆罗洲，以及仍由苏丹统治的英国保护国文莱。",portrait:"portraits/investigator.png"}]},HALE_ROCKETS:{title:"黑尔火箭",theme:"japanese_invasion",lines:[{speaker:"德尔芬",text:"黑尔火箭是英国研发的一系列火箭，被设计成从地面发射，用于攻击日军阵地。黑尔火箭是一种令人生畏的武器，曾被英军应用于多场战役中。",portrait:"portraits/investigator.png"}]},TRIAD:{title:"三合会",theme:"opium",lines:[{speaker:"德尔芬",text:"华人三合会是婆罗洲一个高度组织化的犯罪帝国，管理着岛上的非法经济。",portrait:"portraits/investigator.png"}]},BOMOH:{title:"Bomoh",theme:"occult",lines:[{speaker:"德尔芬",text:"Bomoh是婆罗洲的灵媒和治疗师萨满。他们备受尊敬，经常被请来治疗病人和伤员，以及执行更具精神层面的仪式。",portrait:"portraits/investigator.png"}]},JOURNEY_INTRO:{title:"灵视增强",lines:[{speaker:"德尔芬",text:"记忆网络完整了。我能感觉到共鸣在增强……它正将我拉向小岛之外。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"幸存者们：卢卡斯、卢恩和洛丝。我能看到他们的轨迹了。他们不仅仅是逃跑了，还熬过了一段漫长、艰难的旅程才返回英国。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"我解锁了一条新路径，描绘了他们回乡的旅程。我现在可以跨越海洋追踪他们了。",portrait:"portraits/investigator.png"}]},COLLYER_QUAY:{title:"哥烈码头",lines:[{speaker:"德尔芬",text:"哥烈码头是新加坡一个繁华的地区。它是贸易和商业的枢纽，街道两旁林立着商店和市场。",portrait:"portraits/investigator.png"}]},SAILORS_HOME:{title:"水手之家",lines:[{speaker:"德尔芬",text:"水手之家",portrait:"portraits/investigator.png"}]},BOLSTER:{title:"长枕",lines:[{speaker:"德尔芬",text:"热带地区常见的那种又长又硬的枕头。",portrait:"portraits/investigator.png"}]},ULU:{title:"乌鲁",lines:[{speaker:"德尔芬",text:"乌鲁是婆罗洲茂密的热带雨林。",portrait:"portraits/investigator.png"}]},CAUSEWAY:{title:"长堤",lines:[{speaker:"德尔芬",text:"长堤是连接新加坡与马来西亚的大桥。",portrait:"portraits/investigator.png"}]},DBS:{title:"落难英国侨民",lines:[{speaker:"德尔芬",text:"落难英国侨民：逃离日本占领的英国难民若已丧失一切经济来源，即被归入此官方类别。",portrait:"portraits/investigator.png"}]},MALACCA:{title:"马六甲海峡",lines:[{speaker:"德尔芬",text:"马六甲海峡是分隔马来半岛与印度尼西亚苏门答腊岛的狭长水道。",portrait:"portraits/investigator.png"}]},IPOH:{title:"怡保",lines:[{speaker:"德尔芬",text:"马来亚的主要城市，在入侵初期便已沦陷。",portrait:"portraits/investigator.png"}]},KEDAH:{title:"吉打州",lines:[{speaker:"德尔芬",text:"吉打州位于马来半岛西北部，与泰国接壤。1941年12月下旬，吉打州成为英军在马来亚的战略灾难发生地。这里是日军（在珍珠港事件发生仅数小时后的12月8日）首个入侵的马来亚大陆地区。",portrait:"portraits/investigator.png"}]},BETTY:{title:"贝蒂轰炸机",lines:[{speaker:"德尔芬",text:"盟军赋予马六甲海峡上空巡逻的日本双引擎轰炸机的代号。",portrait:"portraits/investigator.png"}]},NELL:{title:"内尔轰炸机",lines:[{speaker:"德尔芬",text:"盟军赋予另一型日本轰炸机的代号，该机型活跃于马来亚战役期间。",portrait:"portraits/investigator.png"}]},GALLEFACE:{title:"加勒菲斯",lines:[{speaker:"德尔芬",text:"加勒菲斯是科伦坡（锡兰）最具名望的地标，由加勒菲斯绿地（一片宽阔的海滨长廊）和标志性的加勒菲斯大酒店两部分组成。对于卢卡斯而言，加勒菲斯见证着他重返文明的时刻。",portrait:"portraits/investigator.png"}]},DUFF:{title:"达芙糕",lines:[{speaker:"德尔芬",text:"达芙糕是圣诞布丁的俚语称呼。",portrait:"portraits/investigator.png"}]},JAGA:{title:"贾加",lines:[{speaker:"德尔芬",text:"贾加意为守卫。锡克或旁遮普男子在整个英属婆罗洲普遍被雇用为看守，通常身着正式头巾和立领扣扣子的束腰外衣。",portrait:"portraits/investigator.png"}]},FIFTH_COLUMN:{title:"第五纵队",theme:"japanese_invasion",lines:[{speaker:"德尔芬",text:"第五纵队是轴心国在二战期间于盟国境内从事间谍和破坏活动的代称。这一术语由温斯顿·丘吉尔创造，用以描述轴心国瓦解盟军士气与战斗力的种种图谋。",portrait:"portraits/investigator.png"}]},SIS:{title:"SIS",lines:[{speaker:"德尔芬",text:"英国秘密情报局（SIS）是英国第一个情报机构，成立于1909年，负责收集外国势力情报，尤其针对德国和苏联，以及监控第五纵队活动。后更名为军情六处（MI6）。",portrait:"portraits/investigator.png"}]},SECRETARIAT:{title:"殖民地秘书处",lines:[{speaker:"德尔芬",text:"代表总督管理政府事务的文官机构。1941年新加坡沦陷前，秘书处是难民出境签证、通行许可及紧急资助的最终审批机关。",portrait:"portraits/investigator.png"}]},SUMATRA:{title:"苏门答腊",lines:[{speaker:"德尔芬",text:"苏门答腊是印度尼西亚最大的岛屿，荷属东印度的核心瑰宝，也是日本发动太平洋战争的首要目标。",portrait:"portraits/investigator.png"}]},STUKAS:{title:"斯图卡",lines:[{speaker:"德尔芬",text:"斯图卡是指JU-87轰炸机，一种二战期间德国空军使用的著名俯冲轰炸机与对地攻击机。",portrait:"portraits/investigator.png"}]},TRAMP_STEAMER:{title:"不定期货船",lines:[{speaker:"德尔芬",text:"不定期货船是中国南海不起眼的运输主力，一种在各港口间流转、寻找零散货物售卖的商船。",portrait:"portraits/investigator.png"}]},SHOPHOUSE:{title:"骑楼",lines:[{speaker:"德尔芬",text:"骑楼是一种两层联排建筑，底层为商铺，上层为住所。1941年前后，这类建筑已成为迷宫般的难民聚居地，内部用薄木板隔成无数小隔间，尽可能地塞满等待出逃的难民。",portrait:"portraits/investigator.png"}]},ENDING_INTRO:{title:"最终门槛",lines:[{speaker:"洛丝",text:"下午好，有什么可以帮您的吗？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"德尔芬",text:"斯特林夫人？很高兴终于见到您了。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"您可能不认识我，但我对您和您的家人了解颇多，希望能进去为您解释一切。",portrait:"portraits/investigator.png"},{speaker:"洛丝",text:"请进，请进。不好意思家里有点乱，在改卷子呢。我是个老师。",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"德尔芬",text:"非常感谢。",portrait:"portraits/investigator.png"},{speaker:"洛丝",text:"卢恩，有客人！",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"卢恩",text:"来了！",portrait:"portraits/lune_older.png"},{speaker:"德尔芬",text:"卢恩！你长大了，成了一位美丽的女性！",portrait:"portraits/investigator.png"},{speaker:"卢恩",text:"不好意思？我认识您吗？",portrait:"portraits/lune_older.png"},{speaker:"德尔芬",text:"说来话长。斯特林先生在吗？在我解释来意之前，你们最好能所有人都在场。",portrait:"portraits/investigator.png"},{speaker:"洛丝",text:"真对不起，我丈夫还在上班，应该快回来了。",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"德尔芬",text:"那先开始也行。我此行真正想见的那人就在这里。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"卢恩，有一件非常重要的事我必须告诉你。",portrait:"portraits/investigator.png",action:"show_ending_choice"}]},ENDING_1:{title:"真相揭露",lines:[{speaker:"德尔芬",text:"你的哥哥，你的亲生哥哥还活着……古德威尔小姐。",portrait:"portraits/investigator.png"},{speaker:"卢恩",text:"什么？你……你在说什么？你怎么知道我的……不可能啊。",portrait:"portraits/lune_older.png"},{speaker:"洛丝",text:"你是谁？为什么要说这种可怕的话？我们已经为他哀悼过了！",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"德尔芬",text:"对不起，真的很抱歉。这一定让你们大为震惊，但我……我有证据。来，读一读这封信。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"我是一个……通灵者，能看见过去的回声。你哥哥委托了我调查你和你父亲的过去，卢恩。他以为你们两个那天晚上都在婆罗洲罹难了，否则早就在更近的地方寻找你了。",portrait:"portraits/investigator.png"},{speaker:"卢恩",text:"但卢卡斯说……",portrait:"portraits/lune_older.png"},{speaker:"德尔芬",text:"他骗了你，卢恩，骗了你们两个。我不清楚原因，但他把这个真相隐瞒了许多年。",portrait:"portraits/investigator.png"},{speaker:" ",text:"卢卡斯走了进来。"},{speaker:"卢卡斯",text:"怎……怎么了？",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"洛丝将信件甩向卢卡斯。"},{speaker:"洛丝",text:"你打算什么时候告诉我们？还是根本就不打算说？你怎么能这样对她？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:" ",text:"卢卡斯读完了信。"},{speaker:"卢卡斯",text:"对……对不起，我不想失去你们，不想失去这一切。我爱你们，我是真的很爱你们两个。",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"卢恩",text:"我不明白。你说你爱我，却这样伤我的心？你亲眼看见失去父亲和母亲对我造成了多大的伤害，然后你居然决定再杀死我的哥哥？",portrait:"portraits/lune_older.png"},{speaker:"卢卡斯",text:"我太害怕失去你了。他是你的亲生哥哥！他成功、富有……而我一无是处。我不配你们留在我身边。",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"洛丝",text:"那我呢？我们呢？你就没想过这会对我们造成什么影响？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"卢卡斯",text:"我就是不明白你为什么爱我，洛丝。我一直等着你某天清醒过来然后离开我。如果没有卢恩，恐怕你早就离开了。我也怕你和我在一起只是因为顺理成章，其实你值得更好的人。",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"洛丝",text:"你真是疯了。卢卡斯，我是会选择你的。在一百个房间里，一百种人生里，我都会选择你。我爱过你。",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"洛丝",text:"但是现在……",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"洛丝",text:"德尔芬，你能带我们去见卢恩的哥哥吗？……现在就去？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"德尔芬",text:"当然可以。",portrait:"portraits/investigator.png"},{speaker:"洛丝",text:"卢恩？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"卢恩",text:"我曾经那么爱你，那么爱我们这个家。你伤透了我的心，卢卡斯。希望你现在满意了。",portrait:"portraits/lune_older.png"},{speaker:" ",text:"卢恩猛地扯下了颈上的项链，珍珠四散飞溅到房间各处。"},{speaker:"卢恩",text:"我准备好了。",portrait:"portraits/lune_older.png"},{speaker:"德尔芬",text:"我们出发吧，他在不远处的一家咖啡馆等着我们。",portrait:"portraits/investigator.png"},{speaker:" ",text:"卢卡斯一言不发地看着她们离去，就那样站在原地，泪流满面，无法自已。"},{speaker:" ",text:"故事终了。",action:"credits"}]},ENDING_2:{title:"来自彼岸的讯息",lines:[{speaker:"德尔芬",text:"卢恩，这话听起来可能很疯狂，但我是一个通灵者。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"我能感应来自过去的回声，以及那些尚未离开这个世界的灵魂，也可以说是鬼魂。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"你哥哥……你的亲生哥哥，古德威尔小姐。他联系了我……",portrait:"portraits/investigator.png"},{speaker:"卢恩",text:"什么？你……你在说什么？你怎么知道我的……这不可能。",portrait:"portraits/lune_older.png"},{speaker:"德尔芬",text:"你哥哥从另一个世界联系了我。他的灵魂无法安息，想要弄清楚你究竟发生了什么",portrait:"portraits/investigator.png"},{speaker:"洛丝",text:"你是谁？为什么要说这种可怕的话？我们已经为他哀悼过了！",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"德尔芬",text:"对不起，真的很抱歉。这一定让你们大为震惊，我……我没有证据，只有这本日记——里面记录了自婆罗洲的那个夜晚后，你们所经历的一切。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"如果没有通灵的能力，我怎么可能知道这一切？",portrait:"portraits/investigator.png"},{speaker:" ",text:"洛丝和卢恩翻阅着日记，脸色因震惊而变得惨白——那上面写的是她们自己的人生。"},{speaker:"洛丝",text:"我实在无法理解。他是怎么联系到你的？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"德尔芬",text:"我以为我收到了一封信，但那封信其实并不存在。其实我早就应该察觉的，那封信里附有种植园里所有人的照片——他怎么可能有卡南和艾莎的照片呢？",portrait:"portraits/investigator.png"},{speaker:" ",text:"洛丝和卢恩难以置信地盯着德尔芬。"},{speaker:"德尔芬",text:"我知道这听起来很荒诞，真的。我反复权衡了很久，是否应该来这里。",portrait:"portraits/investigator.png"},{speaker:" ",text:"卢卡斯走了进来。"},{speaker:"卢卡斯",text:"怎……怎么了？",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"卢恩冲上去紧紧抱住他，哭了起来。"},{speaker:"洛丝",text:"是卢恩的……哥哥。这位女士说她和他交谈过。",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"德尔芬",text:"也不是，我没说我和他交谈过，是……",portrait:"portraits/investigator.png"},{speaker:"卢卡斯",text:"你是通灵者？等等……你是德尔芬？",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"德尔芬",text:"是的，我们认识吗？",portrait:"portraits/investigator.png"},{speaker:"卢卡斯",text:"不，我们私人没有交集，但军情六处曾雇用过你。你为我们，也为这个国家做了非凡的贡献……我由衷地感谢你。",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"德尔芬",text:"谢谢，我很荣幸。",portrait:"portraits/investigator.png"},{speaker:"洛丝",text:"等等，所以她告诉我们的一切都是真的？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"卢卡斯",text:"以我的所见所闻，不用怀疑她说的话。",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:" ",text:"卢恩从最初的震惊中缓过神来，终于开口了。"},{speaker:"卢恩",text:"所以你是说，我哥哥对我非常牵挂，一直徘徊着想要寻找真相？",portrait:"portraits/lune_older.png"},{speaker:"德尔芬",text:"是的，我就是这个意思。得知你还活着、幸福地生活着的那一刻，他寄给我的那封回声信件就消失了，我感觉到他离开了，终于安息了。",portrait:"portraits/investigator.png"},{speaker:" ",text:"房间里陷入了令人不安的沉默。"},{speaker:"洛丝",text:"茶！真是失礼，您要喝茶吗？",portrait:"portraits/portrait_rose_goodwill.png"},{speaker:"德尔芬",text:"好的，谢谢。",portrait:"portraits/investigator.png"},{speaker:" ",text:"众人在客厅里坐了下来。"},{speaker:"德尔芬",text:"我……我做对了吗？来这里是正确的选择，还是我不该打破你们的安宁？",portrait:"portraits/investigator.png"},{speaker:" ",text:"卢恩拭去眼角的泪水，那是一滴喜悦的泪。"},{speaker:"卢恩",text:"你做了正确的选择，德尔芬。我终于可以释怀了，谢谢你。",portrait:"portraits/lune_older.png"},{speaker:"德尔芬",text:"噢，差点忘了！",portrait:"portraits/investigator.png"},{speaker:" ",text:"德尔芬从口袋里摸出了什么东西。"},{speaker:"德尔芬",text:"来这里之前，我去拜访了塞维利亚小姐，就是想知道我究竟应不应该来。",portrait:"portraits/investigator.png"},{speaker:"卢卡斯",text:"噢，辛西娅在国内？",portrait:"portraits/portrait_lucas_sterling.png"},{speaker:"德尔芬",text:"是的，但她只会待很短的时间，而且必须严格保密。没有人应该知道她在哪里，但我有我的办法。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"总之，卢恩，她想把这个送给你。",portrait:"portraits/investigator.png"},{speaker:" ",text:"德尔芬将一颗孤零零的红色珍珠递给了卢恩。"},{speaker:"德尔芬",text:"她说：'留作纪念，勿忘往昔'。",portrait:"portraits/investigator.png"},{speaker:" ",text:"卢恩将那颗红色珍珠串在了项链正中，脸上绽放出灿烂的笑容。"},{speaker:" ",text:"故事终了。",action:"credits"}]},ROOM_EPIPHANY:{title:"回声探索完毕",lines:[{speaker:"德尔芬",text:"我的直觉告诉我，这个地点的一切已尽数揭开。剩余的时间已不再藏有任何秘密。",portrait:"portraits/investigator.png"}]},BOAT_TUTORIAL:{title:"船屋",lines:[{speaker:"德尔芬",text:"杰里迈亚说卡南在船屋审问卢卡斯，我猜这件事发生在杰里迈亚打电话之前。",portrait:"portraits/investigator.png"},{speaker:" ",text:"若德尔芬选中卢卡斯和卡南，并聚焦于15:00，应该能揭示出那段互动的回声。"},{speaker:" ",text:"时间线上红色气泡中的数字是提示，代表该场景中尚未被你发现的事件线索数量。"},{speaker:" ",text:"通过揭示卢卡斯与卡南的这次互动，书房16:00的提示数字将从2减少到1。"}]},BOAT_TUTORIAL_EMPTY:{title:"船屋",lines:[{speaker:"德尔芬",text:"我还没有足够的信息来揭示这里的回声。得先翻看宾客名单，搞清楚其中几位的身份。",portrait:"portraits/investigator.png"}]},TIDAK_APA:{title:"Tidak Apa",theme:"jargon",lines:[{speaker:"德尔芬",text:"Tidak apa是马来语，意为算了",portrait:"portraits/investigator.png"}]},CYNTHIA_JOURNEY:{title:"辛西娅的旅途",lines:[{speaker:"德尔芬",text:"我想知道辛西娅的旅途进展如何。我知道委托人既不需要也不想要那些信息，但塞维利亚小姐或许对我还有些用处。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"也许该去查看一下她的情况。如果集中精神，我应该能在心灵之眼中感应到她的旅途。",portrait:"portraits/investigator.png"}]},MANIFEST:{lines:[{speaker:"德尔芬",text:"这里有几张关键人员的照片。从感受到的共鸣中，我能判断出哪些人将会起到重要作用。我来把他们添加到案件档案里。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"我只能从周三早上8点开始感应到他们。在那之前，他们离种植园太远，我也不知道他们的汽艇会从海上的哪个方向驶来。",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"非常明确的是，8点时他们都聚集在海岸边，之后才各自散开。",portrait:"portraits/investigator.png"}]},PEARL_2:{lines:[{speaker:"德尔芬",text:"一件物品的主人有时会出乎意料。这颗珍珠理论上应该属于邦恩或杰里迈亚，但它与辛西娅相伴了太久，已经浸染了她的气息。",portrait:"portraits/investigator.png"}]},SAMPAN:{lines:[{speaker:"德尔芬",text:"一种当地的独木舟。",portrait:"portraits/investigator.png"}]},PARANG:{lines:[{speaker:"德尔芬",text:"热带地区典型的多用途刀具与武器，专为砍伐原始丛林中茂密的植被而设计。",portrait:"portraits/investigator.png"}]},CHARLESBROOKE:{lines:[{speaker:"德尔芬",text:"查尔斯·布鲁克……这个名字我有印象。是在哪里见过呢？肯定是在研究婆罗洲时见过，也许是在关于殖民地的词汇表里？",portrait:"portraits/investigator.png"}]},WHITERAJAH:{lines:[{speaker:"德尔芬",text:"就是这里！是白人拉贾！还有一张照片，倒是方便了。",portrait:"portraits/investigator.png",trigger:"reveal:p21"}]},IBAN:{lines:[{speaker:"德尔芬",text:"伊班战士是马来群岛中最传奇、最令人畏惧的勇士。英国人和荷兰人带来了蒸汽船和电报，但伊班人依然是婆罗洲大地的主宰——这是一个文化根植于河流与丛林战争传统的民族。",portrait:"portraits/investigator.png"}]},DUSUN:{lines:[{speaker:"德尔芬",text:"杜顺人是北婆罗洲最大的原住民群体，他们是农耕者，也是骁勇的猎人。",portrait:"portraits/investigator.png"}]},BATU:{title:"巴都沙比",lines:[{speaker:"德尔芬",text:"巴都沙比是山打根的一处沿海地区，因一块天然形成的三足水牛形岩石而闻名，该岩石由侵蚀作用雕琢而成。这处地标位于Karamunting海滩附近，充满了当地传说色彩。人们相信那是一头英勇神牛的化身，它曾与鳄鱼搏斗，拯救了当地村庄。",portrait:"portraits/investigator.png"}]},JUBILEE:{lines:[{speaker:"德尔芬",text:"山打根禧年钟楼是山打根的一处历史地标，英属北婆罗洲殖民时期的著名建筑物。它在战争中得以幸存，但战后不久，城市重建时便遭拆除。",portrait:"portraits/investigator.png"}]},CHINESETOWN:{lines:[{speaker:"德尔芬",text:"唐人街是山打根的商业中心，是一个由骑楼和市集组成的繁华地区，当地华人社区在此开展商业活动。这里充满活力，商贾之声与香料之气交织其中。",portrait:"portraits/investigator.png"}]},BARRAGE_BALLOONS:{lines:[{speaker:"德尔芬",text:"防空气球用于保护伦敦免遭俯冲轰炸机袭击。气球充满氢气并以钢缆系于地面，旨在迫使敌机拉高飞行高度，从而降低轰炸精度。",portrait:"portraits/investigator.png"}]},MIND_EYE:{lines:[{speaker:"德尔芬",text:"我的心灵之眼有什么在涌动，最好去检查一下。",portrait:"portraits/investigator.png"}]},CYNTHIA_ENDING:{lines:[{speaker:" ",text:" ",action:"credits"}]},POST_CREDITS:{lines:[{speaker:" ",text:"1964年2月"},{speaker:" ",text:"前门传来了敲门声。"},{speaker:"德尔芬",text:"会是谁呢？",portrait:"portraits/investigator.png"},{speaker:"德尔芬",text:"来了！",portrait:"portraits/investigator.png"},{speaker:"辛西娅",text:"你好，德尔芬。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"德尔芬",text:"塞维利亚探员？什么风把您吹来了？",portrait:"portraits/investigator.png"},{speaker:"辛西娅",text:"我遇到危险了，不知道还能信任谁。我需要你的帮助。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"德尔芬",text:"什么？出什么事了？",portrait:"portraits/investigator.png"},{speaker:"辛西娅",text:"我们最优秀的特工之一，也是我非常亲密的朋友，失踪了。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"辛西娅",text:"我最后一次和他联系时，他说他发现了重大线索，但有人在跟踪他。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"辛西娅",text:"我非常担心他已经遭遇了不测，而且我怀疑是内部的人做的。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:"德尔芬",text:"这真是太不幸了。他叫什么名字？",portrait:"portraits/investigator.png"},{speaker:"辛西娅",text:"他叫亚瑟，亚瑟·波德威斯尔。",portrait:"portraits/portrait_cynthia_seville.png"},{speaker:" ",text:" ",action:"tbc"}]}};export{r as DIALOGUE};
